let transcriptText = '';

if ($json.text) {
  transcriptText = $json.text;
} else if ($json.data && typeof $json.data === 'string') {
  transcriptText = $json.data;
} else if ($binary?.data?.data) {
  const buffer = Buffer.from($binary.data.data, 'base64');
  transcriptText = buffer.toString('utf-8').replace(/\0/g, '').trim();
}

const lead = $('Check - Supported File Type').item.json;

return {
  lead_row: lead['row_number'],
  transcript_text: transcriptText,
  lead_name: lead['Name'],
  lead_email: lead['Email'],
  lead_company: lead['Company'],
  lead_sales_rep: lead['Sales Rep'],
  lead_last_contact: lead['Last Contact'],  
};
